SELECT status, COUNT(*) AS invitation_count
FROM event_invitations
GROUP BY status;

SELECT MAX(notification_count) AS max_notifications_per_day
FROM (
  SELECT DATE(notification_date) AS notification_day, COUNT(*) AS notification_count
  FROM notifications
  GROUP BY DATE(notification_date)
);

SELECT setting_value
FROM calendar_settings
WHERE user_id = 1 AND calendar_id = 0;

SELECT COUNT(event_id) AS total_events
FROM events
WHERE calendar_id = (SELECT calendar_id FROM calendars WHERE user_id = 0 AND is_default = 1);

SELECT user_id, COUNT(*) AS total_calendars
FROM calendars
GROUP BY user_id;

SELECT COUNT(*) 
FROM event_invitations
WHERE status = 'pending';

SELECT c.calendar_id, c.calendar_name, (SELECT MAX(LENGTH(description)) FROM calendars WHERE LENGTH(description) > 0) AS longest_description_length
FROM calendars c
WHERE LENGTH(c.description) > 0;

SELECT event_name, start_date, is_recurring
FROM events
WHERE is_recurring = 1 AND event_id IN (
  SELECT event_id FROM reminders
)
ORDER BY start_date ASC;

SELECT status
FROM event_invitations
WHERE invitation_id = 0;

SELECT access_level, COUNT(*) AS share_count
FROM calendar_shares
GROUP BY access_level;

SELECT DISTINCT u.username
FROM users u
JOIN calendar_shares cs ON u.user_id = cs.user_id;
